1	import { StringUtils, SyntaxKind, ts } from "@ts-morph/common";
2	import { CodeBlockWriter } from "../../codeBlockWriter";
3	import { Node, SourceFile } from "../../compiler";
4	import { Structure } from "../../structures";
5	import {
6	  appendCommaToText,
7	  getEndPosFromIndex,
8	  getInsertPosFromIndex,
9	  getNodesToReturn,
10	  getRangeWithoutCommentsFromArray,
11	  verifyAndGetIndex,
12	} from "../helpers";
13	import { NodeHandlerFactory } from "../nodeHandlers";
14	import { InsertionTextManipulator } from "../textManipulators";
15	import { doManipulation } from "./doManipulation";
16	
17	export interface InsertIntoParentTextRangeOptions {
18	  insertPos: number;
19	  newText: string;
20	  parent: Node;
21	  replacing?: {
22	    textLength: number;
23	    nodes?: Node[];
24	  };
25	  customMappings?: (newParentNode: ts.Node, newSourceFile: ts.SourceFile) => { currentNode: Node; newNode: ts.Node }[];
26	}
27	
28	/**
29	 * Inserts a text range into a parent.
30	 */
31	export function insertIntoParentTextRange(opts: InsertIntoParentTextRangeOptions) {
32	  const { insertPos, newText, parent } = opts;
33	
34	  doManipulation(
35	    parent._sourceFile,
36	    new InsertionTextManipulator({
37	      insertPos,
38	      newText,
39	      replacingLength: opts.replacing?.textLength,
40	    }),
41	    new NodeHandlerFactory().getForParentRange({
42	      parent,
43	      start: insertPos,
44	      end: insertPos + newText.length,
45	      replacingLength: opts.replacing?.textLength,
46	      replacingNodes: opts.replacing?.nodes,
47	      customMappings: opts.customMappings,
48	    }),
49	  );
50	}
51	
52	export interface InsertIntoTextRangeOptions {
53	  sourceFile: SourceFile;
54	  insertPos: number;
55	  newText: string;
56	}
57	
58	/**
59	 * Inserts a text range into a source file.
60	 */
61	export function insertIntoTextRange(opts: InsertIntoTextRangeOptions) {
62	  const { insertPos, newText, sourceFile } = opts;
63	
64	  doManipulation(
65	    sourceFile,
66	    new InsertionTextManipulator({
67	      insertPos,
68	      newText,
69	    }),
70	    new NodeHandlerFactory().getForRange({
71	      sourceFile,
72	      start: insertPos,
73	      end: insertPos + newText.length,
74	    }),
75	  );
76	}
77	
78	export interface InsertIntoCommaSeparatedNodesOptions {
79	  currentNodes: Node[];
80	  insertIndex: number;
81	  newText: string;
82	  parent: Node;
83	  useTrailingCommas: boolean;
84	  useNewLines?: boolean;
85	  surroundWithSpaces?: boolean;
86	}
87	
88	export function insertIntoCommaSeparatedNodes(opts: InsertIntoCommaSeparatedNodesOptions) {
89	  // todo: this function could use a bit of clean up
90	  const { currentNodes, insertIndex, parent } = opts;
91	  const previousNode = currentNodes[insertIndex - 1] as Node | undefined;
92	  const previousNonCommentNode = getPreviousNonCommentNode();
93	  const nextNode = currentNodes[insertIndex] as Node | undefined;
94	  const nextNonCommentNode = getNextNonCommentNode();
95	  const separator = opts.useNewLines ? parent._context.manipulationSettings.getNewLineKindAsString() : " ";
96	  const parentNextSibling = parent.getNextSibling();
97	  const isContained = parentNextSibling != null && (
98	    parentNextSibling.getKind() === SyntaxKind.CloseBraceToken || parentNextSibling.getKind() === SyntaxKind.CloseBracketToken
99	  );
100	  let { newText } = opts;
101	
102	  if (previousNode != null) {
103	    prependCommaAndSeparator();
104	
105	    if (nextNonCommentNode != null || opts.useTrailingCommas)
106	      appendCommaAndSeparator();
107	    else if (opts.useNewLines || opts.surroundWithSpaces)
108	      appendSeparator();
109	    else
110	      appendIndentation();
111	
112	    const nextEndStart = nextNode == null ? (isContained ? parentNextSibling!.getStart(true) : parent.getEnd()) : nextNode.getStart(true);
113	    const insertPos = (previousNonCommentNode || previousNode).getEnd();
114	    insertIntoParentTextRange({
115	      insertPos,
116	      newText,
117	      parent,
118	      replacing: { textLength: nextEndStart - insertPos },
119	    });
120	  } else if (nextNode != null) {
121	    if (opts.useNewLines || opts.surroundWithSpaces)
122	      prependSeparator();
123	
124	    if (nextNonCommentNode != null || opts.useTrailingCommas)
125	      appendCommaAndSeparator();
126	    else
127	      appendSeparator();
128	
129	    const insertPos = isContained ? parent.getPos() : parent.getStart(true);
130	    insertIntoParentTextRange({
131	      insertPos,
132	      newText,
133	      parent,
134	      replacing: { textLength: nextNode.getStart(true) - insertPos },
135	    });
136	  } else {
137	    if (opts.useNewLines || opts.surroundWithSpaces) {
138	      prependSeparator();
139	
140	      if (opts.useTrailingCommas)
141	        appendCommaAndSeparator();
142	      else
143	        appendSeparator();
144	    } else {
145	      appendIndentation();
146	    }
147	
148	    insertIntoParentTextRange({
149	      insertPos: parent.getPos(),
150	      newText,
151	      parent,
152	      replacing: { textLength: parent.getNextSiblingOrThrow().getStart() - parent.getPos() },
153	    });
154	  }
155	
156	  function prependCommaAndSeparator() {
157	    if (previousNonCommentNode == null) {
158	      prependSeparator();
159	      return;
160	    }
161	
162	    const originalSourceFileText = parent.getSourceFile().getFullText();
163	    const previousNodeNextSibling = previousNonCommentNode.getNextSibling();
164	    let text = "";
165	    if (previousNodeNextSibling != null && previousNodeNextSibling.getKind() === SyntaxKind.CommaToken) {
166	      appendNodeTrailingCommentRanges(previousNonCommentNode);
167	      text += ",";
168	      if (previousNonCommentNode === previousNode)
169	        appendNodeTrailingCommentRanges(previousNodeNextSibling);
170	      else
171	        appendCommentNodeTexts();
172	    } else {
173	      text += ",";
174	      if (previousNonCommentNode === previousNode)
175	        appendNodeTrailingCommentRanges(previousNonCommentNode);
176	      else
177	        appendCommentNodeTexts();
178	    }
179	
180	    prependSeparator();
181	    newText = text + newText;
182	
183	    function appendCommentNodeTexts() {
184	      const lastCommentRangeEnd = getLastCommentRangeEnd(previousNode!) || previousNode!.getEnd();
185	      text += originalSourceFileText.substring(previousNonCommentNode!.getEnd(), lastCommentRangeEnd);
186	    }
187	
188	    function appendNodeTrailingCommentRanges(node: Node) {
189	      const lastCommentRangeEnd = getLastCommentRangeEnd(node);
190	      if (lastCommentRangeEnd == null)
191	        return;
192	      text += originalSourceFileText.substring(node.getEnd(), lastCommentRangeEnd);
193	    }
194	
195	    function getLastCommentRangeEnd(node: Node) {
196	      const commentRanges = node.getTrailingCommentRanges();
197	      const lastCommentRange = commentRanges[commentRanges.length - 1];
198	      return lastCommentRange?.getEnd();
199	    }
200	  }
201	
202	  function getPreviousNonCommentNode() {
203	    for (let i = insertIndex - 1; i >= 0; i--) {
204	      if (!Node.isCommentNode(currentNodes[i]))
205	        return currentNodes[i];
206	    }
207	    return undefined;
208	  }
209	
210	  function getNextNonCommentNode() {
211	    for (let i = insertIndex; i < currentNodes.length; i++) {
212	      if (!Node.isCommentNode(currentNodes[i]))
213	        return currentNodes[i];
214	    }
215	    return undefined;
216	  }
217	
218	  function prependSeparator() {
219	    if (!StringUtils.startsWithNewLine(newText))
220	      newText = separator + newText;
221	  }
222	
223	  function appendCommaAndSeparator() {
224	    newText = appendCommaToText(newText);
225	    appendSeparator();
226	  }
227	
228	  function appendSeparator() {
229	    if (!StringUtils.endsWithNewLine(newText))
230	      newText += separator;
231	    appendIndentation();
232	  }
233	
234	  function appendIndentation() {
235	    if (opts.useNewLines || StringUtils.endsWithNewLine(newText)) {
236	      if (nextNode != null)
237	        newText += parent.getParentOrThrow().getChildIndentationText();
238	      else
239	        newText += parent.getParentOrThrow().getIndentationText();
240	    }
241	  }
242	}
243	
244	export interface InsertIntoBracesOrSourceFileOptionsWriteInfo {
245	  previousMember: Node | undefined;
246	  nextMember: Node | undefined;
247	  isStartOfFile: boolean;
248	}
249	
250	export interface InsertIntoBracesOrSourceFileOptions {
251	  parent: Node;
252	  children: Node[];
253	  index: number;
254	  write: (writer: CodeBlockWriter, info: InsertIntoBracesOrSourceFileOptionsWriteInfo) => void;
255	}
256	
257	/**
258	 * Used to insert non-comma separated nodes into braces or a source file.
259	 */
260	export function insertIntoBracesOrSourceFile(opts: InsertIntoBracesOrSourceFileOptions) {
261	  const { parent, index, children } = opts;
262	  const fullText = parent._sourceFile.getFullText();
263	  const childSyntaxList = parent.getChildSyntaxListOrThrow();
264	  const insertPos = getInsertPosFromIndex(index, childSyntaxList, children);
265	  const endPos = getEndPosFromIndex(index, parent, children, fullText);
266	  const replacingLength = endPos - insertPos;
267	  const newText = getNewText();
268	
269	  doManipulation(
270	    parent._sourceFile,
271	    new InsertionTextManipulator({ insertPos, replacingLength, newText }),
272	    new NodeHandlerFactory().getForParentRange({
273	      parent: childSyntaxList,
274	      start: insertPos,
275	      end: insertPos + newText.length,
276	      replacingLength,
277	    }),
278	  );
279	
280	  function getNewText() {
281	    // todo: make this configurable
282	    const writer = parent._getWriterWithChildIndentation();
283	    opts.write(writer, {
