15	const versionLibFolder = new Map<string, string>();
16	function getCompilerLibFolder(version: string) {
17	  if (!versionLibFolder.has(version))
18	    versionLibFolder.set(version, getFolder());
19	
20	  return versionLibFolder.get(version)!;
21	
22	  function getFolder() {
23	    const basePath = path.join(__dirname, `../../../../../common/node_modules/`);
24	    const versionPath = path.join(basePath, `typescript-${version}/lib`);
25	    if (fileSystem.directoryExistsSync(versionPath))
26	      return versionPath;
